var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저건…… 부사장님이 저렇게 대단한 실력자였어?","JPN":"あれは……副社長ってあんなにすごい実力者だったの？","ENG":"What...? Was the Vice President such an impressive warrior?","TWN":"哇……副總這麼能打喔？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이거 깜짝 놀랐는데요?","JPN":"これは驚きましたね。","ENG":"I'm a bit shocked.","TWN":"嚇死我啦！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"앞으로는 부사장님 앞에서 말조심을 좀 해야겠어요.","JPN":"これから副社長の前では口を慎むことにしましょう。","ENG":"From now on, I should watch my mouth when speaking in front of her.","TWN":"以後在副總面前說話要放尊重一點。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 저대로 혼자 싸우게 둬도 되는 거야?","JPN":"でも、あのまま一人で戦わせてもいいわけ？","ENG":"But is it really okay to let her fight by herself like this?","TWN":"但放副總自己一個人真的沒關係嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저긴 적들의 한가운데라고, 이대로 두면 부사장님은……","JPN":"あそこは敵陣の真ん中だよ、このままじゃ副社長は……","ENG":"She’s right in the center of their forces. At this rate, she’ll...","TWN":"那邊全都是敵人，這樣下去副總她……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"부사장님. 저도 같이 남는 게 좋지 않을까요?","JPN":"副社長。私も一緒に残った方がいいんじゃないですか？","ENG":"Vice President, wouldn’t it be better if I also stay back with you?","TWN":"副總，我也一起留下好嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"부사장님만큼은 아니겠지만…… 저도 펜릴 소대의 일원이니까요.","JPN":"副社長には及びませんが……私もフェンリル小隊の隊員ですから。","ENG":"Although I may not be as skilled as you... I too am a member of Fenrir Squad.","TWN":"雖然我不比副總……但我也是芬里爾小隊的一員。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"……아니요. 시윤 군. 여긴 저 혼자로도 충분합니다.","JPN":"……いいえ。シリュウさん。ここは私一人でも十分です。","ENG":"...No, Shiyoon. I will be sufficient.","TWN":"……不，時雲，這邊我自己可以應付。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"그러니 가서 꼭 미나 양을 지켜주세요.","JPN":"ですから、行ってぜひミナさんを守ってください。","ENG":"Therefore, please protect Mina at all costs.","TWN":"你一定要去保護米娜。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"스승님이 사라진 이상, 미나 양을 지킬 사람은 시윤 군뿐이니까요.","JPN":"師匠が消えた以上、ミナさんを守れる人はシリュウさんだけですから。","ENG":"With Master absent at the moment, you’re the only one who can protect Mina.","TWN":"師父消失後，能夠保護米娜的人就只剩你而已。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어째서죠? 부사장님은 미나 양을 그다지 맘에 들어 하지 않는 줄 알았는데요.","JPN":"どうしてですか？　副社長はミナさんをあまり気に入ってないと思っていましたが。","ENG":"Why do you care about her so much? I thought that you didn’t have a high opinion of Mina?","TWN":"為什麼？我還以為副總你不怎麼喜歡米娜？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"물론 전 미나양을 그리 좋아하지는 않습니다.","JPN":"もちろん私はミナさんがあまり好きではありません。","ENG":"Of course, I’d be lying if I said that I did.","TWN":"我是不怎麼喜歡米娜，"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"하지만 그녀에게 빚이 있는 것도 사실이죠.","JPN":"ですが、彼女に借りがあることもまた事実です。","ENG":"However, I do have a debt that I must repay to her.","TWN":"但她確實有債。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"빚…… 말인가요?","JPN":"借り……ですか？","ENG":"A... debt?","TWN":"有……債？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"……아주 오래 전의 이야기입니다.","JPN":"……だいぶ前のことです。","ENG":"...It’s an old story.","TWN":"……這已經是很久以前的事，"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"클리파 차원에 도달해서 클리포트 게임을 중지시키려면, 반드시 미나 양이 그 곳에 있어야 합니다. 그것이 룰이니까요.","JPN":"クリファ次元に到達してクリフォトゲームを中止させるには、必ずミナさんがそこにいなければなりません。それがルールですから。","ENG":"In order to reach the Qlipha Dimension and put an end to the Qliphoth Game, Mina must be there in person. That’s the rule.","TWN":"抵達逆卡巴拉次元後，若想停止逆卡巴拉遊戲，米娜就必須在那個地方，這是規則。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"그리고 만약 그 과정에서 미나양이 사망한다면……","JPN":"そしてもしその途中、ミナさんが死亡すると……","ENG":"And if Mina happens to die along the way...","TWN":"米娜若是在過程中死亡……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};